import type { FC } from "react";

import { FaqPage as FaqPageWidget } from "@/widgets/faq-page";

export const FaqPage: FC = () => <FaqPageWidget />;

export type FaqItem = {
  question: string;
  answer: string;
  hasEmailLink?: boolean;
};

export type FaqSection = {
  id: string;
  title: string;
  items: FaqItem[];
};

export const PROCESS_TIMELINE_TABLE = {
  steps: [
    "1. Quote Request Analysis",
    "2. Indicative Offer Validity",
    "3. Item Delivery Window",
    "4. Physical Inspection",
    "5. Confirmed Offer Validity",
    "6. Payment Execution",
    "7. Payment Processing - Crypto",
    "7. Payment Processing - PayPal",
    "8. Buyback Period",
    "9. Buyback Renewals",
    "10. Final Extension",
  ],
  timings: [
    "5 minutes (next business day if after hours)",
    "48 hours (2 calendar days)",
    "2 business days after acceptance",
    "Target 24 hours from item receipt",
    "48 hours (2 calendar days)",
    "Immediate upon acceptance",
    "5-15 minutes",
    "Instant (fee) or 1-3 business days",
    "30 calendar days from payment",
    "Up to 3× 30-day extensions (fees apply)",
    "Up to 3× 30-day extensions (fees apply)",
  ],
};

export const FAQ_SECTIONS: FaqSection[] = [
  {
    id: "valuation-authentication",
    title: "Valuation & Authentication",
    items: [
      {
        question: "How can I create a sell or buyback request?",
        answer:
          "Create an account, submit your asset details and images, and request a valuation. Once you accept an offer, LuxFlow confirms next steps for authentication, logistics, and settlement.",
      },
      {
        question: "How is the price of my item determined?",
        answer:
          "Valuations are based on current market data, comparable transactions, asset condition, and expert review. Final pricing reflects real, executable market demand at the time of assessment.",
      },
      {
        question: "How is my item authenticated?",
        answer:
          "All assets undergo mandatory authentication using a combination of expert inspection and technology-assisted verification. High-value assets may be reviewed by multiple specialists before an offer is finalised.",
      },
      {
        question: "Is it secure to send my item via courier?",
        answer:
          "Yes. Where applicable, LuxFlow arranges insured pickup and secure transport through Brinks. Assets are insured while in transit and during approved storage.",
      },
      {
        question: "Why are there fees associated with the offer?",
        answer:
          "Fees reflect the cost of authentication, secure logistics, insurance, storage, and platform services. Any applicable fees are disclosed clearly before you accept an offer.",
      },
      {
        question: "How long does it take to receive funds after accepting an offer?",
        answer:
          "Payment is executed immediately after you accept the Confirmed Offer. Processing times depend on your selected method: crypto transfers complete in 5-15 minutes; PayPal transfers are instant (with fee) or 1-3 days (standard).",
      },
      {
        question: "Does LuxFlow run any credit checks?",
        answer:
          "No. LuxFlow does not perform credit checks. Offers are based solely on the asset and standard identity and compliance verification.",
      },
    ],
  },
  {
    id: "sell-buyback",
    title: "Sell & Buyback",
    items: [
      {
        question: "What is the difference between a Final Sale and Sale with Buyback?",
        answer:
          "A Final Sale is a permanent sale with no option to repurchase. A Sale with Buyback allows you to sell your item and repurchase it within 30 calendar days by refunding the amount you received.",
      },
      {
        question: "How does the buyback option work?",
        answer:
          "After completing a Sale with Buyback, you have 30 calendar days from payment execution to exercise your Right of Reversal. To repurchase, provide written notice and refund the full amount received. LuxFlow will then return your item via insured logistics.",
      },
      {
        question: "What happens if I don't exercise my buyback option?",
        answer:
          "If you do not repurchase within the 30-day Buyback Period, the transaction automatically converts to a Final Sale. Ownership transfers permanently to LuxFlow and you forfeit all rights to the item.",
      },
      {
        question: "Can I extend the buyback period?",
        answer:
          "Yes. You may renew the Buyback Period for an additional 30 calendar days, up to 3 renewals. Renewal fees are calculated using the same methodology as the initial Platform/Service Fee. A final 7-day extension may be granted at LuxFlow's discretion.",
      },
      {
        question: "Who pays for return shipping on a buyback?",
        answer:
          "The Seller is responsible for shipping costs when exercising the Right of Reversal.",
      },
      {
        question: "Is the Platform/Service Fee refundable if I buy back my item?",
        answer:
          "No. All Platform/Service Fees are non-refundable, including when you exercise the Right of Reversal.",
      },
    ],
  },
  {
    id: "general-questions",
    title: "General Questions",
    items: [
      {
        question: "What assets does LuxFlow support?",
        answer:
          "LuxFlow supports selected luxury assets, including watches, jewellery, handbags, and other high-value collectibles, subject to review.",
      },
      {
        question: "Do I retain ownership during the valuation process?",
        answer:
          "Yes. You retain ownership until you formally accept an offer and LuxFlow confirms acceptance.",
      },
      {
        question: "Are valuations binding?",
        answer:
          "Valuations are indicative until physical inspection and authentication are completed. Final offers may be adjusted if material discrepancies are identified.",
      },
      {
        question: "Can I decline an offer after receiving it?",
        answer:
          "Yes. You are under no obligation to proceed until you formally accept an offer.",
      },
      {
        question: "Does LuxFlow custody my funds or crypto?",
        answer:
          "No. LuxFlow does not custody client funds. Payments and payouts are processed via regulated third-party providers.",
      },
      {
        question: "Is my personal data secure?",
        answer:
          "Yes. Personal data is handled in accordance with applicable data protection laws and LuxFlow's Privacy Policy, using trusted third-party providers where required.",
      },
      {
        question: "What payment methods are available?",
        answer:
          "LuxFlow offers crypto (with network processing times of 5-15 minutes) and PayPal (instant with fee, or 1-3 days standard) to your designated account or wallet.",
      },
      {
        question: "How do I contact LuxFlow support?",
        answer:
          "You can reach our support team at contact@luxflow.com or through the contact form on the Platform.",
        hasEmailLink: true,
      },
    ],
  },
  {
    id: "pricing-fees",
    title: "Pricing & Fees",
    items: [
      {
        question: "How can I create a valuation request?",
        answer:
          "Create an account, submit your asset details and images through the Quote Request form. You will receive an Indicative Offer Amount within the Platform.",
      },
      {
        question: "How long does it take to receive a price quote?",
        answer:
          "Quote Requests are analysed within 5 minutes during business hours, or by early next day if submitted after hours.",
      },
      {
        question: "Is the quote I receive the final price?",
        answer:
          "No. The initial quote is an Indicative Offer Amount based on the information you provide. The final Confirmed Offer Amount is issued after Physical Inspection and authentication.",
      },
      {
        question: "How long is the Indicative Offer valid?",
        answer:
          "The Indicative Offer Amount expires after 48 hours (2 calendar days). After this period, you must submit a new Quote Request.",
      },
      {
        question: "Are there any hidden fees or charges?",
        answer:
          "No. The Platform/Service Fee includes all costs for authentication, insurance, storage, handling, and logistics. Fees are disclosed before you accept any offer.",
      },
      {
        question: "What factors affect my item's price?",
        answer:
          "Pricing is based on brand, model, condition, provenance, documentation, market demand, and comparable sales data at the time of valuation.",
      },
      {
        question: "Do you price all types of luxury items?",
        answer:
          "LuxFlow focuses on luxury watches, designer jewelry, luxury handbags, fine art, and valuable collectibles. Items outside these categories may be considered on a case-by-case basis.",
      },
      {
        question: "Can I decline the quote?",
        answer:
          "Yes. You are under no obligation to proceed. If you decline the Confirmed Offer Amount after Physical Inspection, your item will be returned at your expense.",
      },
      {
        question: "How long is the Confirmed Offer valid?",
        answer:
          "The Confirmed Offer Amount expires after 48 hours (2 calendar days) from issuance.",
      },
      {
        question: "Can I talk to someone before submitting?",
        answer:
          "Yes. Contact contact@luxflow.com with questions before submitting a Quote Request.",
        hasEmailLink: true,
      },
    ],
  },
  {
    id: "process-timeline",
    title: "Process Timeline",
    items: [
      {
        question: "What is the typical timeline for a transaction?",
        answer:
          "See the timeline table below for each stage of the process.",
      },
    ],
  },
  {
    id: "additional-questions",
    title: "Additional Questions",
    items: [
      {
        question: "What documents do I need to provide?",
        answer:
          "You will need to provide government-issued identification for KYC verification. For the item, we recommend providing certificates of authenticity, original receipts, warranty cards, and any appraisal reports if available.",
      },
      {
        question: "What happens if my item fails authentication?",
        answer:
          "If an item fails authentication or is determined to be counterfeit, LuxFlow will not proceed with the transaction. The item will be returned to you at your expense.",
      },
      {
        question: "What happens if I don't deliver my item within the acceptance window?",
        answer:
          "If you accept the Indicative Offer but do not deliver your item (via drop-off or scheduled pickup) within 2 business days, the offer expires and you must submit a new Quote Request.",
      },
      {
        question: "What currencies can I receive payment in?",
        answer:
          "Payments are processed via crypto (to your designated wallet) or PayPal (to your PayPal account or linked bank account).",
      },
      {
        question: "Is there a minimum or maximum transaction value?",
        answer:
          "Contact LuxFlow for information on minimum and maximum transaction values, which may vary by asset category and transaction type.",
      },
      {
        question: "Where is my item stored during the Buyback Period?",
        answer:
          "Items are stored in secure, climate-controlled facilities with professional handling protocols and security monitoring. Insurance coverage is included.",
      },
      {
        question: "Can I track my item during the process?",
        answer:
          "Yes. You will receive updates at each stage: receipt, inspection, offer, and settlement. Transaction status is also visible in your account dashboard.",
      },
      {
        question: "How do buyback renewals work?",
        answer:
          "You may extend your Buyback Period by 30 calendar days, up to 3 times. Renewal fees are calculated using the same methodology as the initial Platform/Service Fee and will be confirmed to you before each renewal. A final 7-day extension may be granted at LuxFlow's sole discretion.",
      },
    ],
  },
];

