"use client";

import type { ReactNode } from "react";
import { useEffect, useRef, useState } from "react";

import { cn } from "@/shared/lib/ui/cn";
import { FAQ_SECTIONS, PROCESS_TIMELINE_TABLE } from "../model/constants";

const CONTACT_EMAIL = "contact@luxflow.com";

function renderAnswer(answer: string, hasEmailLink?: boolean): ReactNode {
  if (!hasEmailLink) {
    return answer;
  }
  const parts = answer.split(CONTACT_EMAIL);
  return (
    <>
      {parts[0]}
      <a
        className="font-bold text-[#001A8C] underline"
        href={`mailto:${CONTACT_EMAIL}`}
      >
        {CONTACT_EMAIL}
      </a>
      {parts[1]}
    </>
  );
}

function ProcessTimelineTable() {
  return (
    <div className="mt-4 overflow-hidden rounded-xl border border-[#D6D3D1]">
      <div className="flex">
        <div className="flex flex-1 flex-col">
          <div className="flex h-12 items-center border-[#D6D3D1] border-b bg-[#EDE9E3]/60 px-2">
            <span className="font-medium font-new-sans text-[#A8A29E] text-sm tracking-[-0.14px]">
              Step
            </span>
          </div>
          {PROCESS_TIMELINE_TABLE.steps.map((step) => (
            <div
              className="flex h-[60px] items-center border-[#D6D3D1] border-b bg-[#F5F3EF] px-2 last:border-b-0"
              key={step}
            >
              <span className="font-new-sans text-[#44403C] text-sm tracking-[-0.14px]">
                {step}
              </span>
            </div>
          ))}
        </div>
        <div className="flex flex-1 flex-col border-[#D6D3D1] border-l">
          <div className="flex h-12 items-center border-[#D6D3D1] border-b bg-[#EDE9E3]/60 px-2">
            <span className="font-medium font-new-sans text-[#A8A29E] text-sm tracking-[-0.14px]">
              Timing
            </span>
          </div>
          {PROCESS_TIMELINE_TABLE.timings.map((timing, index) => (
            <div
              className="flex h-[60px] items-center border-[#D6D3D1] border-b bg-[#F5F3EF] px-2 last:border-b-0"
              key={index}
            >
              <span className="font-new-sans text-[#44403C] text-sm tracking-[-0.14px]">
                {timing}
              </span>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
}

export function FaqPage() {
  const [activeCategory, setActiveCategory] = useState(FAQ_SECTIONS[0].id);
  const isScrollingRef = useRef(false);

  useEffect(() => {
    const observers: IntersectionObserver[] = [];

    for (const section of FAQ_SECTIONS) {
      const element = document.getElementById(section.id);
      if (!element) continue;

      const observer = new IntersectionObserver(
        ([entry]) => {
          if (entry.isIntersecting && !isScrollingRef.current) {
            setActiveCategory(section.id);
          }
        },
        { rootMargin: "-40% 0px -55% 0px", threshold: 0 }
      );

      observer.observe(element);
      observers.push(observer);
    }

    return () => {
      for (const observer of observers) {
        observer.disconnect();
      }
    };
  }, []);

  const handleCategoryClick = (sectionId: string) => {
    setActiveCategory(sectionId);
    isScrollingRef.current = true;
    const element = document.getElementById(sectionId);
    if (element) {
      element.scrollIntoView({ behavior: "smooth", block: "start" });
    }
    setTimeout(() => {
      isScrollingRef.current = false;
    }, 800);
  };

  return (
    <div className="my-[48px] bg-background md:my-[62px]">
      {/* Page header */}
      <div
        className="flex w-full items-center justify-center bg-center bg-cover bg-no-repeat px-6 py-10"
        style={{
          backgroundImage: "url('/new-design-images/FAQs Title.svg')",
          aspectRatio: "1720 / 222",
        }}
      >
        <h1
          className="font-extralight font-new-serif text-4xl text-[#44403C] leading-[1.1] tracking-[0px] min-[1172px]:text-[56px]"
          style={{ fontFeatureSettings: "'liga' off" }}
        >
          Frequently asked questions
        </h1>
      </div>

      {/* Two-column layout */}
      <div className="mx-auto flex max-w-[1720px] px-4 min-[1172px]:px-10">
        {/* Left sticky sidebar */}
        <div className="relative hidden w-[340px] flex-shrink-0 lg:block">
          <div className="sticky top-52 my-20">
            <p className="mb-9 font-bold font-new-sans text-[#44403C] text-[20px] leading-6 tracking-[-0.2px]">
              Explore questions by categories
            </p>
            <div className="flex flex-col gap-4 border-[#D6D3D1] border-l pl-5">
              {FAQ_SECTIONS.map((section) => (
                <button
                  className={cn(
                    "text-left font-new-sans text-base leading-[1.5] tracking-[-0.16px] transition-colors",
                    activeCategory === section.id
                      ? "font-bold text-[#001A8C]"
                      : "font-normal text-[#44403C] hover:text-[#001A8C]"
                  )}
                  key={section.id}
                  onClick={() => handleCategoryClick(section.id)}
                  type="button"
                >
                  {section.title}
                </button>
              ))}
            </div>
          </div>
        </div>

        {/* Right FAQ content */}
        <div className="min-w-0 flex-1">
          <div className="max-w-[800px] lg:ml-[214px]">
            {FAQ_SECTIONS.map((section, sectionIndex) => (
              <section
                className={cn(
                  "py-10 md:py-[60px]",
                  sectionIndex > 0 && "border-[#D6D3D1] border-t"
                )}
                id={section.id}
                key={section.id}
              >
                <h2 className="mb-5 font-extralight font-new-serif text-2xl text-[#44403C] leading-[1.2] min-[1172px]:text-[30px]">
                  {section.title}
                </h2>

                <div className="flex flex-col">
                  {section.items.map((item, itemIndex) => (
                    <div
                      className={cn(
                        "py-2",
                        itemIndex > 0 && "border-[#D6D3D1] border-t"
                      )}
                      key={item.question}
                    >
