      <div className="mx-auto flex max-w-[1720px] px-4 min-[1172px]:px-10">
        {/* Left FAQ content */}
        <div className="min-w-0 flex-1">
          <div className="max-w-[800px] lg:mr-[214px]">
            {FAQ_SECTIONS.map((section, sectionIndex) => (
              <section
                className={cn(
                  "py-10 md:py-[60px]",
                  sectionIndex > 0 && "border-[#D6D3D1] border-t"
                )}
                id={section.id}
                key={section.id}
              >
                <h2 className="mb-5 font-extralight font-new-serif text-2xl text-[#44403C] leading-[1.2] min-[1172px]:text-[30px]">
                  {section.title}
                </h2>

                <div className="flex flex-col">
                  {section.items.map((item, itemIndex) => (
                    <div
                      className={cn(
                        "py-2",
                        itemIndex > 0 && "border-[#D6D3D1] border-t"
                      )}
                      key={item.question}
                    >
                      <p className="font-medium font-new-sans text-[#44403C] text-[18px] leading-[1.3]">
                        {item.question}
                      </p>
                      <p className="mt-2 font-new-sans text-[#44403C] text-base leading-[1.5] tracking-[-0.16px]">
                        {renderAnswer(item.answer, item.hasEmailLink)}
                      </p>
                      {section.id === "process-timeline" && itemIndex === 0 && (
                        <ProcessTimelineTable />
                      )}
                    </div>
                  ))}
                </div>
              </section>
            ))}
          </div>
        </div>

        {/* Right sticky sidebar */}
        <div className="relative hidden w-[340px] flex-shrink-0 lg:block">
          <div className="sticky top-52 my-20">
            <p className="mb-9 font-bold font-new-sans text-[#44403C] text-[20px] leading-6 tracking-[-0.2px]">
              Explore questions by categories
            </p>
            <div className="flex flex-col gap-4 border-[#D6D3D1] border-l pl-5">
              {FAQ_SECTIONS.map((section) => (
                <button
                  className={cn(
                    "text-left font-new-sans text-base leading-[1.5] tracking-[-0.16px] transition-colors",
                    activeCategory === section.id
                      ? "font-bold text-[#001A8C]"
                      : "font-normal text-[#44403C] hover:text-[#001A8C]"
                  )}
                  key={section.id}
                  onClick={() => handleCategoryClick(section.id)}
                  type="button"
                >
                  {section.title}
                </button>
              ))}
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}
